import React, { useState } from 'react';
import { loginUsuario } from '../services/authService';

const Login = () => {
    const [form, setForm] = useState({ matricula: '', password: '' });

    const handleSubmit = async (e) => {
        e.preventDefault();
        const resultado = await loginUsuario(form.matricula, form.password);
        
        if (resultado === "BIENVENIDO_ADMIN") {
            alert("¡Acceso total concedido, riempy!");
            // Aquí luego pondremos la lógica para ir al inventario
        } else {
            alert("Matrícula o contraseña incorrecta");
        }
    };

    return (
        <div style={{ textAlign: 'center', marginTop: '100px' }}>
            <h1>Isla Tecnológica</h1>
            <form onSubmit={handleSubmit}>
                <input 
                    type="text" 
                    placeholder="Tu Matrícula" 
                    onChange={(e) => setForm({...form, matricula: e.target.value})} 
                /><br/><br/>
                <input 
                    type="password" 
                    placeholder="Contraseña" 
                    onChange={(e) => setForm({...form, password: e.target.value})} 
                /><br/><br/>
                <button type="submit">Entrar al Sistema</button>
            </form>
        </div>
    );
};

export default Login;
